#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=20005;
struct node
{
	int v,w;
};
vector<node> g[N];
int n,dp[N],f[N],ans,m,mx;
void dfs(int u,int fa)
{
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i].v;
		if(v==fa) continue;
		f[v]=g[u][i].w;
		dfs(v,u);
		dp[u]=max(dp[u],dp[v]+f[v]);
	}
	if(dp[u]+f[u]>=m)
	{
		dp[u]=0;
		ans++;
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		int num;
		cin>>num;
		for(int j=1;j<=num;j++)
		{
			int x,y;
			cin>>x>>y;
			g[i].push_back(node{x,y});
			mx=max(mx,y);
		}
	}
	cin>>m;
	if(mx>=m)
	{
		cout<<"No solution.";
		return 0;
	}
	dfs(1,0);
	cout<<ans;
	return 0;
}
